<script>
    document.addEventListener('DOMContentLoaded', () => {
        const toggleBtn = document.getElementById('support-toggle');
        const optionsContainer = document.getElementById('support-options');
        const iconChat = document.getElementById('icon-chat');
        const iconClose = document.getElementById('icon-close');

        if (toggleBtn && optionsContainer && iconChat && iconClose) {
            let isOpen = false;

            toggleBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                isOpen = !isOpen;
                if (isOpen) {
                    // Open options
                    optionsContainer.classList.remove('scale-0', 'translate-y-10', 'opacity-0', 'pointer-events-none');
                    optionsContainer.classList.add('scale-100', 'translate-y-0', 'opacity-100');
                    
                    // Rotate and toggle main button icons
                    iconChat.classList.add('hidden');
                    iconClose.classList.remove('hidden');
                    toggleBtn.classList.remove('bg-[#cc1f26]', 'hover:bg-[#b0161c]');
                    toggleBtn.classList.add('bg-[#1e293b]', 'hover:bg-[#0f172a]');
                } else {
                    closeMenu();
                }
            });

            // Close when clicking outside
            document.addEventListener('click', () => {
                if (isOpen) closeMenu();
            });

            function closeMenu() {
                isOpen = false;
                optionsContainer.classList.remove('scale-100', 'translate-y-0', 'opacity-100');
                optionsContainer.classList.add('scale-0', 'translate-y-10', 'opacity-0', 'pointer-events-none');
                
                iconClose.classList.add('hidden');
                iconChat.classList.remove('hidden');
                toggleBtn.classList.remove('bg-[#1e293b]', 'hover:bg-[#0f172a]');
                toggleBtn.classList.add('bg-[#cc1f26]', 'hover:bg-[#b0161c]');
            }
        }
    });
</script>
